import { MakeLogicType, afterMount, connect, kea, key, path, props } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'
import { teamLogic } from 'scenes/teamLogic'

import type { Experiment } from '~/types'


export interface ExperimentTabLogicProps {
    featureFlagId: number
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface experimentTabLogicValues {
    currentProjectId: number | string; // teamLogic
    relatedExperiments: Experiment[];
    relatedExperimentsLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface experimentTabLogicActions {
    loadRelatedExperiments: () => any;
    loadRelatedExperimentsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadRelatedExperimentsSuccess: (relatedExperiments: Experiment[], payload?: any) => {
        relatedExperiments: Experiment[];
        payload?: any;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface experimentTabLogicMeta {
    key: number;
}

export type experimentTabLogicType = MakeLogicType<experimentTabLogicValues, experimentTabLogicActions, ExperimentTabLogicProps, experimentTabLogicMeta>;

export const experimentTabLogic = kea<experimentTabLogicType>([
    path(['scenes', 'experiments', 'experimentTabLogic']),
    props({} as ExperimentTabLogicProps),
    key((props) => props.featureFlagId),
    connect(() => ({ values: [teamLogic, ['currentProjectId']] })),
    loaders(({ props, values }) => ({
        relatedExperiments: [
            [] as Experiment[],
            {
                loadRelatedExperiments: async () => {
                    const response = await api.get(
                        `api/projects/${values.currentProjectId}/experiments/?feature_flag_id=${props.featureFlagId}`
                    )
                    return response.results || []
                },
            },
        ],
    })),
    afterMount(({ actions }) => {
        actions.loadRelatedExperiments()
    }),
])
